VALUES
  ('judicial-57112235-moex-00777', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '有關假釋出監受刑人刑期變更事宜，下列敘述何者錯誤？', '["假釋出監受刑人刑期變更者，監獄於接獲相關執行指揮書後，應依刑法第77條規定重新核算，並 提報其假釋審查會決議後，報請法務部辦理維持或廢止假釋", "假釋期間已屆滿且假釋未經撤銷者，已執行保護管束日數全部計入刑期", "假釋尚未期滿者，已執行保護管束日數應於日後再假釋時，不得折抵假釋及保護管束期間", "受刑人於假釋核准後，未出監前，發生重大違背紀律情事，監獄應立即報請法務部停止其假釋處分 之執行，並即提報假釋審查會決議後，再報請法務部廢止假釋"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00778', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄應設假釋審查會，有關委員人數之規定，下列敘述何者正確？', '["7人至11人", "8人至12人", "4人至6人", "3人至5人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00779', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法中有關受刑人釋放之相關規定，下列敘述何者錯誤？', '["執行期滿者，應於其刑期終了之次日午前釋放之", "核准假釋者，應於保護管束命令送交監獄後24小時內釋放之。但有特殊事由者，得於指定日期辦理 釋放", "假釋釋放時，由監獄給與假釋證書，並告知如不於特定時間內向執行保護管束檢察署檢察官報到， 得撤銷假釋之規定", "受赦免者，應於公文到達後至遲24小時內釋放之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00780', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '受刑人依監獄行刑法第134條第1項規定，提起復審而不服其決定，或提起復審逾2個月不為決定或 延長復審決定期間逾2個月不為決定者，應向監獄所在地或執行保護管束地之地方法院行政訴訟庭提 起下列何種訴訟？', '["給付訴訟", "確認訴訟", "撤銷訴訟", "課予義務訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00781', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄二級受刑人已適於社會生活，合於法定假釋之規定者，得報請假釋，所謂適於社會生活的認定， 下列敘述何者錯誤？', '["出監後須有適當之職業與技能", "有固定之住所或居所", "社會對其無不良觀感", "須得到被害者的原諒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 47, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00782', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依監獄行刑法及其施行細則關於假釋之規定，下列敘述何者錯誤？', '["依刑法第77條第2項第3款接受毒癮戒治之受刑人，應附具曾受治療之紀錄及個案自我控制再犯 預防成效評估報告，如顯有再犯之虞，不得報請假釋", "受刑人於假釋核准後，未出監前，發生重大違背紀律情事，監獄應立即報請法務部停止其假釋處分 之執行。所稱「未出監前」包含在監內接續執行拘役或罰金易服勞役等刑罰，尚未出監者", "監獄召開假釋審查會前，應以適當之方式給予受刑人陳述意見之機會", "除法律另有規定外，受刑人得向監獄請求閱覽、抄錄、複製假釋審查相關資料"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00783', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '監獄行刑法規定執行死刑之時間，應於何時告知受刑人本人？', '["前3天", "前2天", "前1天", "當日"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57112235-moex-00784', 'judicial-57112235', 'judicial-57112235-moex-110-879fbd32', 'sub-judicial-57112235-04', NULL, 'single_choice', '依外役監條例第14條有關縮短刑期之規定，下列敘述何者正確？', '["受刑人經遴選至外役監執行之當月，即依外役監條例第14條辦理縮短刑期", "外役監未編級受刑人不符每月縮短刑期之規定", "外役監受刑人每執行1個月，第四級受刑人每月縮短刑期4日；第三級受刑人每月縮短刑期8日", "外役監受刑人每執行1個月，第二級受刑人每月縮短刑期10日；第一級受刑人每月縮短刑期14日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:53+00:00", "source_pdf_sha1": "e7701438d5a8", "answer_pdf_sha1": "11d44f73843c", "source_family": "moex-gov-tw", "moex": {"exam_code": "110130", "c": "207", "s": "0705", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "監獄行刑法概要", "year": "110", "exam_name": "110年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格者取得法官遴選資格考...", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "監所管理員"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00001', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '聯合國於1979年通過「消除對婦女一切形式歧視公約」（CEDAW），是國際婦女權益發展的重要里程碑。 公約第 4 條明定為了加速實現男女事實上的平等，各國政府可以採取「暫行特別措施」，且這些措施應在 男女機會和待遇平等的目的達到之後，停止採用。下列何項法令或政策之規定，最符合所謂「暫行特別措 施」之精神？', '["地方制度法規定，各選舉區選出之直轄市議員、縣（市）議員、鄉（鎮、市）民代表名額達四人者，應 有婦女當選名額一人", "民法第1089條修正後規定，子女姓氏由「原則從父姓」改為由父母書面約定之", "性別平等工作法第15條規定，雇主於女性受僱者分娩前後，應使其停止工作，給予產假8星期", "性別平等工作法第16條規定，受僱者任職滿6個月後，於每一子女滿3歲前，得申請育嬰留職停薪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00002', 'judicial-57f41407', 'judicial-57f41407-moex-114-b3f42868', 'sub-judicial-57f41407-01', NULL, 'single_choice', '一般而言對於民主政治之形成應具備基本要件，下列何者不屬之？', '["主權在民之民意政治", "容許輪替之責任政治", "多數治理之多數決制", "選舉應有高度投票率"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:35+00:00", "source_pdf_sha1": "1bb7c1ea3915", "answer_pdf_sha1": "219ca4b54b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "114120", "c": "301", "s": "0205", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "公民與英文", "year": "114", "exam_name": "114年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
